    int len = arr.length; // Variable of length
    a = 0, b = len -1; // calculation of locaton, the a is total index of array which reduce with the number of account for []
    int temp;
    while (a < b){
        temp = arr[a];
        arr[a] = arr[b];
        arr[b] = temp;
        a++;
        b--;
    }
    return arr;
}
